// Extrai marcadores [[MEDIA:...]] do texto do Supervisor.
// O marcador é removido do texto (pra não ir pro paciente) e vira uma lista em media_keys.
const out = String($json.output ?? $json.text ?? '');
const re = /\[\[MEDIA:([^\]]+)\]\]/gi;

const keys = [];
let m;
while ((m = re.exec(out)) !== null) {
  keys.push(m[1]);
}

const media_keys = Array.from(new Set(keys
  .flatMap((s) => String(s).split(/[;,\r\n]+/g))
  .flatMap((s) => String(s).split(','))
  .map((s) => s.trim().toLowerCase())
  .filter(Boolean)
));


const output_clean = out
  .replace(re, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return items.map((item) => ({
  json: {
    ...item.json,
    output: output_clean,
    media_keys,
  },
}));

// Remove URLs duplicadas mantendo a ordem (evita enviar a mesma foto 2x)
return items.map((item) => {
  const json = item.json ?? {};

  const urls =
    Array.isArray(json.image_urls) ? json.image_urls :
    Array.isArray(json.data?.[0]?.image_urls) ? json.data[0].image_urls :
    [];

  const seen = new Set();
  const unique = [];
  for (const u of urls) {
    const s = String(u ?? '').trim();
    if (!s) continue;
    if (seen.has(s)) continue;
    seen.add(s);
    unique.push(s);
  }

  const newJson = { ...json, image_urls: unique };

  // Mantém consistência caso algum node use data[0].image_urls
  if (Array.isArray(newJson.data) && newJson.data[0] && typeof newJson.data[0] === 'object') {
    newJson.data = [...newJson.data];
    newJson.data[0] = { ...newJson.data[0], image_urls: unique };
  }

  return { json: newJson, binary: item.binary };
});

const currentState = $('Buscar Cliente1').first().json.atendimento_ia || '';
const isPaused = currentState === 'pause';
const newState = isPaused ? 'reativada' : 'pause';
const confirmMsg = isPaused
  ? '▶️ IA reativada! O robô voltou a responder.'
  : '⏸️ IA pausada! Você assumiu a conversa.';

return [{
  json: {
    new_state: newState,
    confirm_msg: confirmMsg,
    telefone: $('Info2').item.json.telefone,
    id_conversa: $('Info2').item.json.id_conversa,
    id_conta: $('Info2').item.json.id_conta,
    url_chatwoot: $('Info2').item.json.url_chatwoot
  }
}];
